   151→nsresult nsObserverService::Create(const nsIID& aIID, void** aInstancePtr) {
   152→  LOG(("nsObserverService::Create()"));
   153→
   154→  RefPtr<nsObserverService> os = new nsObserverService();
   155→
   156→  // The memory reporter can not be immediately registered here because
   157→  // the nsMemoryReporterManager may attempt to get the nsObserverService
   158→  // during initialization, causing a recursive GetService.
   159→  NS_DispatchToCurrentThread(
   160→      NewRunnableMethod("nsObserverService::RegisterReporter", os,
   161→                        &nsObserverService::RegisterReporter));
   162→
   163→  return os->QueryInterface(aIID, aInstancePtr);
   164→}
